import React, { useState } from "react";
import "./Feedback.css";

function Feedback() {
  const [courseId, setCourseId] = useState("");
  const [userId, setUserId] = useState("");
  const [rating, setRating] = useState("");
  const [comments, setComments] = useState("");

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log({ courseId, userId, rating, comments });
  };

  return (
    <>
    <form className="feedback-form" onSubmit={handleSubmit}>
      <label>Course ID</label>
      <input type="text" value={courseId} onChange={(e) => setCourseId(e.target.value)} required />
      <label>User ID</label>
      <input type="text" value={userId} onChange={(e) => setUserId(e.target.value)} required />
      <label>Rating</label>
      <input type="number" value={rating} onChange={(e) => setRating(e.target.value)} min="1" max="5" required />
      <label>Comments</label>
      <textarea value={comments} onChange={(e) => setComments(e.target.value)} required />
      <button type="submit">Submit Feedback</button>
    </form>
    </>
  );
}

export default Feedback;
